php -r '
$items=json_decode(file_get_contents("resources/fullfeed/items_all.json"),true);
$plus=json_decode(file_get_contents("resources/fullfeed/plus.json"),true);
$done=file_get_contents(".github/port.md");
$plusUrls=[]; foreach($plus as $p){$plusUrls[]=$p["data"]["url"]??"";}
foreach($items as $item){
  $url=$item["data"]["url"]??"";
  if(in_array($url,$plusUrls,true)) continue;
  if(str_contains($done,$url)) continue;
  echo json_encode(["name"=>$item["name"]??null,"url"=>$url,"selector"=>$item["data"]["selector"]??null,"xpath"=>$item["data"]["xpath"]??null], JSON_UNESCAPED_UNICODE|JSON_UNESCAPED_SLASHES),"\n";
  break;
}
'

